1.5 Opción 2 (usando el decorador @property):

class CuentaBancariaV2:
    def __init__(self, titular, saldo):
        self.__titular = titular
        self.__saldo = saldo

    def __validar_cantidad(self, cantidad):
        # Verifica si la cantidad es válida para retiro
        if cantidad &lt;= 0:
            print("Error: La cantidad debe ser mayor a cero.")
            return False
        elif cantidad &gt; self.__saldo:
            print("Error: Fondos insuficientes.")
            return False
        return True

    def depositar(self, cantidad):
        if cantidad &gt; 0:
            self.__saldo += cantidad
            print(f"Depósito exitoso. Nuevo saldo: ${self.__saldo}")
        else:
            print("Error: La cantidad a depositar debe ser positiva.")

    def retirar(self, cantidad):
        if self.__validar_cantidad(cantidad):
            self.__saldo -= cantidad
            print(f"Retiro exitoso. Nuevo saldo: ${self.__saldo}")

    # Getter con @property para el saldo
    @property
    def saldo(self):
        return self.__saldo

    # Setter con @property para el saldo
    @saldo.setter
    def saldo(self, nuevo_saldo):
        if nuevo_saldo &gt;= 0:
            self.__saldo = nuevo_saldo
        else:
            print("Error: El saldo no puede ser negativo.")

    # Getter con @property para el titular
    @property
    def titular(self):
        """Getter para obtener el titular"""
        return self.__titular

    # Setter con @property para el saldo
    @titular.setter
    def titular(self, nuevo_titular):
        """Setter para modificar el titular"""
        if isinstance(nuevo_titular, str) and nuevo_titular.strip():
            self.__titular = nuevo_titular
        else:
            print("Error: El titular debe ser un nombre válido.")


